#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100001];
        scanf("%s", S);
        int N = strlen(S);
        int nim_sum = 0;
        for (int i = 0; i < N; i++) {
            int j = i;
            while (j < N && S[j] != ')') {
                j++;
            }
            if (j < N) {
                nim_sum ^= (j - i + 1);
                i = j;
            }
        }
        if (nim_sum != 0) {
            printf("ATM\n");
        } else {
            printf("Bob\n");
        }
    }
    return 0;
}

